-- Two NEW academy guides adapted (rewritten clean, Matjar-accurate) from the
-- user's 2024 source articles. No Salla/Sayl/Aramex references; no online-payment
-- claims; deduped and de-SEO'd. Idempotent on slug.
insert into public.academy_guides
  (slug, category, level, title, title_en, excerpt, read_min, emoji, blocks, sort_order)
values
  ('winning-sales-plan','growth','intermediate','كيف تبني خطة مبيعات ناجحة','How to build a winning sales plan','خطة المبيعات ليست ترفاً للشركات الكبيرة، بل خريطة طريق تحوّل جهدك اليوميّ إلى نتائج قابلة للقياس. تعرّف على عناصرها وكيف تحلّل أداءك.',6,'📈','[{"t":"p","text":"كثيرٌ من أصحاب المتاجر يبيعون بلا خطة؛ يجرّبون هنا وهناك، فتضيع جهودهم بلا اتّجاه. خطة المبيعات ليست وثيقةً معقّدة، بل إجابةٌ واضحة عن سؤال: ماذا أبيع، ولمن، وكيف أقيس نجاحي؟"},{"t":"h","text":"العناصر التي تصنع خطّةً ناجحة"},{"t":"ol","items":["تحليل السوق: افهم عميلك ومنافسك قبل أن تبيع؛ ما الذي يحتاجه، وما الذي يميّزك عن غيرك.","أهدافٌ قابلة للقياس: «أريد أن أبيع أكثر» ليس هدفاً؛ أمّا «مئة طلبٍ هذا الشهر» فهدفٌ تستطيع قياسه.","استراتيجيّةٌ واضحة: حدّد منتجاتك الأساسيّة وقنواتك (واتساب، إنستغرام، متجرك) وركّز عليها بدل أن تتشتّت.","خطّة تنفيذ: قسّم الهدف إلى خطواتٍ أسبوعيّة، فالهدف الكبير يُنجَز بخطواتٍ صغيرة.","المراجعة المستمرّة: راجع أرقامك كلّ أسبوع لا كلّ سنة؛ فالخطّة الجيّدة مرنةٌ تتعدّل مع السوق."]},{"t":"h","text":"كيف تحلّل مبيعاتك"},{"t":"p","text":"لا يمكنك تحسين ما لا تقيسه. راقب هذه الزوايا الأربع:"},{"t":"ul","items":["الأرقام: كم بِعت هذا الشهر مقارنةً بالماضي؟ وأيّ منتجٍ يبيع أكثر؟","العملاء: من هم عملاؤك الأكثر شراءً؟ وما الذي يعيدهم إليك؟","التوقيت: متى تبلغ مبيعاتك ذروتها؟ استعدّ لها بالمخزون والعروض.","العوامل الخارجيّة: المواسم والأعياد والوضع الاقتصاديّ كلّها تؤثّر، فخطّط لها."]},{"t":"tip","text":"استعِن بلوحة التقارير في متجر لمتابعة مبيعاتك، وبحاسبة الأرباح في مركز الأدوات لتعرف ربحك الحقيقيّ لا مبيعاتك فحسب."},{"t":"h","text":"ابدأ صغيراً، وكن واقعيّاً"},{"t":"p","text":"لا تنتظر خطّةً مثاليّة لتبدأ. ابدأ بهدفٍ واحدٍ واضحٍ لهذا الشهر، ونقطة قوّةٍ واحدةٍ تميّزك، ثمّ عدّل كلّ أسبوع. فالاستمرار والمراجعة أهمّ من الكمال."}]'::jsonb,6),
  ('ecommerce-basics','ecommerce','beginner','أساسيّات التجارة الإلكترونيّة للتاجر المبتدئ','E-commerce basics for the new merchant','ما التجارة الإلكترونيّة، ولماذا صارت ضرورةً لكلّ نشاطٍ في لبنان؟ ومن أين تبدأ متجرك الأوّل بثقة؟',5,'🛒','[{"t":"p","text":"التجارة الإلكترونيّة ببساطة أن تعرض منتجاتك وخدماتك وتبيعها عبر الإنترنت، دون تقيّدٍ بمكانٍ أو ساعات عمل. ولم تعد رفاهيةً، بل صارت الطريقة التي يبحث بها الناس ويشترون كلّ يوم."},{"t":"h","text":"لماذا تهمّك التجارة الإلكترونيّة"},{"t":"ul","items":["وصولٌ أوسع: متجرك مفتوحٌ لكلّ لبنان، لا لمن يمرّ أمام محلّك فحسب.","متاحٌ دائماً: يتصفّح عميلك ويطلب في أيّ وقت، حتى وأنت نائم.","بياناتٌ تفيدك: تعرف ما يبحث عنه عملاؤك وما يبيع أكثر، فتقرّر بالأرقام لا بالحدس.","تكلفةٌ أقلّ: تبدأ بلا إيجار محلٍّ ولا تكاليف كبيرة."]},{"t":"h","text":"من أين تبدأ؟"},{"t":"ol","items":["افتح متجرك مجّاناً على متجر، وأضف اسمك وشعارك ووصفاً واضحاً لنشاطك.","أضف منتجاتك بصورٍ نظيفة ووصفٍ يبيّن قيمتها للعميل، لا مواصفاتها فحسب.","فعّل قنوات التواصل: زرّ واتساب يجعل الطلب والسؤال بضغطة.","اتّفق على التوصيل: حدّد مناطقك ورسومك بوضوح حتى يطمئنّ العميل.","ابنِ الثقة: التقييمات وسرعة الردّ وسياسة إرجاعٍ واضحة تحوّل الزائر إلى مشترٍ."]},{"t":"tip","text":"ابدأ بعددٍ قليلٍ من المنتجات المصوّرة جيّداً بدل أن ترفع كلّ شيءٍ دفعةً واحدة؛ فمتجرٌ صغيرٌ ومرتّبٌ يبيع أكثر من متجرٍ كبيرٍ فوضويّ."},{"t":"h","text":"الثقة قبل البيع"},{"t":"p","text":"العميل اللبنانيّ يشتري ممّن يثق به. رقمٌ واضحٌ للتواصل، وردٌّ سريع، وصورٌ حقيقيّة، وتقييماتٌ من عملاءٍ سابقين — هذه ما يصنع أوّل عمليّة بيع، ويعيد العميل مرّةً بعد مرّة."}]'::jsonb,7)
on conflict (slug) do update set
  category = excluded.category, level = excluded.level, title = excluded.title,
  title_en = excluded.title_en, excerpt = excluded.excerpt, read_min = excluded.read_min,
  emoji = excluded.emoji, blocks = excluded.blocks, sort_order = excluded.sort_order,
  updated_at = now();
